# Session management using Redis
class RedisSessionInterface:
    def __init__(self, redis_client, prefix='session:'):
        self.redis_client = redis_client
        self.prefix = prefix

    def open_session(self, app, request):
        session_id = request.cookies.get(app.session_cookie_name)
        if not session_id:
            return {}
        
        try:
            session_data = self.redis_client.get(self.prefix + session_id)
            if session_data:
                return json.loads(session_data)
        except:
            pass
        return {}

    def save_session(self, app, session, response):
        session_id = session.get('_id')
        if not session_id:
            session_id = hashlib.sha256(str(time.time()).encode()).hexdigest()
            session['_id'] = session_id
        
        try:
            self.redis_client.setex(
                self.prefix + session_id,
                3600,  # 1 hour expiry
                json.dumps(dict(session))
            )
            response.set_cookie(
                app.session_cookie_name,
                session_id,
                httponly=True,
                secure=True,
                samesite='Lax'
            )
        except:
            pass

# Apply session interface
app.session_interface = RedisSessionInterface(redis_client)

# Caching decorator for expensive queries
def cache_result(timeout=300):
    def decorator(f):
        @functools.wraps(f)
        def decorated_function(*args, **kwargs):
            # Create cache key
            cache_key = f"{f.__name__}:{hashlib.md5(str(args + tuple(sorted(kwargs.items()))).encode()).hexdigest()}"
            
            try:
                # Try to get from cache
                cached_result = redis_client.get(cache_key)
                if cached_result:
                    return json.loads(cached_result)
            except:
                pass
            
            # Execute function and cache result
            result = f(*args, **kwargs)
            
            try:
                redis_client.setex(cache_key, timeout, json.dumps(result))
            except:
                pass
            
            return result
        return decorated_function
    return decorator

